using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// --- 1. Get strongly-typed JsonTypeInfo<T> ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

JsonTypeInfo<Person> typed = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Typed metadata  → Type={typed.Type.Name}, Kind={typed.Kind}");

// --- 2. Probe without throwing (TryGetTypeInfo) ---
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"TryGet succeeded → {info!.Type.Name}");
}

// Now try with an empty resolver — no metadata available
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // resolves nothing
};

if (empty.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("Unexpected: found metadata in empty resolver");
}
else
{
    Console.WriteLine("TryGet returned false → no metadata (no exception thrown)");
}

record Person(string Name, int Age);

